from datetime import datetime, timedelta

class RateLimitExceeded(Exception):
    pass

class RateLimiter:
    def __init__(self, max_requests: int, window_seconds: int):
        self.max_requests = max_requests
        self.window_seconds = window_seconds
        self.requests = []

    def check_rate_limit(self, client_id: str) -> bool:
        current_time = datetime.now()
        # Supprimer les requêtes trop anciennes
        self.requests = [t for t in self.requests if current_time - t <= timedelta(seconds=self.window_seconds)]

        if len(self.requests) >= self.max_requests:
            raise RateLimitExceeded(f"Rate limit exceeded for client {client_id}")

        self.requests.append(current_time)
        return True

def execute():
    return RateLimiter(max_requests=10, window_seconds=60)
